import type { FieldComponentProps } from './types';

export function EmailField({
  formField,
  fieldConfig,
  className,
  ...rest
}: FieldComponentProps) {
  const { ref, ...field } = formField;
  return (
    <input
      ref={ref}
      {...field}
      type="email"
      placeholder={fieldConfig.placeholder}
      className={className}
      {...rest}
    />
  );
}
